from dataclasses import dataclass
from decimal import Decimal, ROUND_HALF_UP
from typing import Any, Dict, List, Optional, Union
import uuid


Currency = Union[str, None]


@dataclass
class User:
    role: str


def process_payment(user: Any, cart_items: List[Dict[str, Any]], payment_details: Dict[str, Any]) -> Dict[str, Any]:
    if user is None or not hasattr(user, "role"):
        raise ValueError("Invalid user: missing role")

    role = str(getattr(user, "role")).lower().strip()
    role_discounts = {
        "basic": Decimal("0.00"),
        "premium": Decimal("0.15"),
        "enterprise": Decimal("0.30"),
    }
    if role not in role_discounts:
        raise ValueError(f"Invalid role: {role}")

    if not isinstance(cart_items, list) or len(cart_items) == 0:
        raise ValueError("cart_items must be a non-empty list")

    currency: Currency = payment_details.get("currency") if isinstance(payment_details, dict) else None
    if not currency:
        currency = "USD"

    subtotal = Decimal("0.00")
    for idx, item in enumerate(cart_items):
        if not isinstance(item, dict):
            raise ValueError(f"Invalid cart item at index {idx}: must be a dict")
        if "price" not in item:
            raise ValueError(f"Cart item at index {idx} missing 'price'")
        price = Decimal(str(item["price"]))
        if price < 0:
            raise ValueError(f"Cart item at index {idx} has negative price")
        qty = item.get("quantity", 1)
        try:
            qty_int = int(qty)
        except Exception:
            raise ValueError(f"Cart item at index {idx} has invalid quantity")
        if qty_int <= 0:
            raise ValueError(f"Cart item at index {idx} must have quantity >= 1")
        subtotal += (price * Decimal(qty_int))

    discount_rate = role_discounts[role]
    discount_amount = (subtotal * discount_rate).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)
    total = (subtotal - discount_amount).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

    if not isinstance(payment_details, dict):
        raise ValueError("payment_details must be a dict")

    method = str(payment_details.get("method", "")).lower().strip()
    if method not in {"card", "bank", "wallet"}:
        raise ValueError("Unsupported payment method")

    if total <= 0:
        raise ValueError("Total must be greater than zero")

    payment_id = str(uuid.uuid4())
    status = "succeeded"

    return {
        "payment_id": payment_id,
        "status": status,
        "currency": currency,
        "role": role,
        "discount_percent": int((discount_rate * Decimal("100")).to_integral_value(rounding=ROUND_HALF_UP)),
        "subtotal": str(subtotal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)),
        "discount": str(discount_amount),
        "total": str(total),
        "payment_method": method,
        "metadata": payment_details.get("metadata", {}),
    }